import type { Props } from '/virtual/types';
import { CurrentWeather, WeatherStats, ForecastStrip } from './components';

export function WeatherCard(props: Props) {
  return (
    <Card style={{ padding: 'var(--spacing-lg)', maxWidth: '400px', width: '100%' }}>
      <article>
        <CurrentWeather city={props.city} temperature={props.temperature} condition={props.condition} unit={props.unit || '°C'} />
        <Spacer />
        <WeatherStats humidity={props.humidity} windSpeed={props.windSpeed} />
        <Spacer />
        <Divider />
        <Spacer />
        <ForecastStrip forecast={props.forecast} />
      </article>
    </Card>
  );
}


