export function ForecastStrip(props: ForecastStripProps) {
  return (
    <Box padding={16}>
      <Row gap={16} justify="start">
        {props.forecast.map((f, i) => (
          <Box key={i} padding={8} background="var(--ggui-color-surfaceVariant)" borderRadius="md">
            <Stack align="center" gap={4}>
              <Text variant="label">{f.day}</Text>
              <Icon name={f.icon} size={24} />
              <Row gap={8}>
                <Text variant="body" weight="semibold">{f.high}°</Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{f.low}°</Text>
              </Row>
            </Stack>
          </Box>
        ))}
      </Row>
    </Box>
  );
}


